 {"id":"bd-10i.3.2","title":"Implement PackedRgba with Porter-Duff blending","description":"# Implement PackedRgba with Porter-Duff blending

## Objective
Implement the 4-byte packed RGBA color type with efficient alpha compositing.

## Technical Design

### Layout
[R:8][G:8][B:8][A:8] in native endian as u32

### Why Packed?
- 4 bytes fits in Cell's 16-byte budget
- Fast equality comparison (single u32 compare)
- SIMD-friendly for bulk operations

### Porter-Duff 'Over' Compositing
Result = src + dst × (1 - src.alpha)

This is the standard way to composite translucent colors:
- Fully opaque src (alpha=255): result = src
- Fully transparent src (alpha=0): result = dst
- Partial: blend proportionally

### Implementation
#[derive(Clone, Copy, PartialEq, Eq, Default)]
#[repr(transparent)]
pub struct PackedRgba(pub u32);

impl PackedRgba {
    pub const TRANSPARENT: Self = Self(0);
    pub const BLACK: Self = Self::rgb(0, 0, 0);
    pub const WHITE: Self = Self::rgb(255, 255, 255);

    #[inline]
    pub const fn rgb(r: u8, g: u8, b: u8) -> Self {
        Self(((r as u32) << 24) | ((g as u32) << 16) 
             | ((b as u32) << 8) | 255)
    }

    #[inline]
    pub const fn rgba(r: u8, g: u8, b: u8, a: u8) -> Self {
        Self(((r as u32) << 24) | ((g as u32) << 16) 
             | ((b as u32) << 8) | (a as u32))
    }

    // Component accessors
    #[inline] pub fn r(&self) -> u8 { (self.0 >> 24) as u8 }
    #[inline] pub fn g(&self) -> u8 { (self.0 >> 16) as u8 }
    #[inline] pub fn b(&self) -> u8 { (self.0 >> 8) as u8 }
    #[inline] pub fn a(&self) -> u8 { self.0 as u8 }

    /// Porter-Duff 'over': src over dst
    #[inline]
    pub fn over(self, dst: Self) -> Self {
        let src_a = self.a() as u32;
        if src_a == 255 { return self; }
        if src_a == 0 { return dst; }

        let inv_a = 255 - src_a;
        let r = ((self.r() as u32 * 255) + (dst.r() as u32 * inv_a)) / 255;
        let g = ((self.g() as u32 * 255) + (dst.g() as u32 * inv_a)) / 255;
        let b = ((self.b() as u32 * 255) + (dst.b() as u32 * inv_a)) / 255;
        let a = src_a + ((dst.a() as u32 * inv_a) / 255);

        Self::rgba(r as u8, g as u8, b as u8, a as u8)
    }

    /// Apply uniform opacity [0.0, 1.0]
    #[inline]
    pub fn with_opacity(self, opacity: f32) -> Self {
        let a = ((self.a() as f32) * opacity.clamp(0.0, 1.0)) as u8;
        Self((self.0 & 0xFFFF_FF00) | (a as u32))
    }
}

