### Cell Mutation with Scissor/Opacity

```rust
impl Buffer {
    /// Set cell at (x, y), respecting scissor and opacity.
    ///
    /// - If (x, y) is outside current scissor, write is ignored
    /// - Opacity is multiplied into cell colors
    /// - Alpha compositing performed if bg is transparent
    /// - Wide chars (width 2) set CONTINUATION at x+1
    #[instrument(skip(self, cell), fields(x, y, in_scissor = self.in_scissor(x, y)))]
    pub fn set(&mut self, x: u16, y: u16, mut cell: Cell) {
        if !self.in_scissor(x, y) {
            trace!("Write outside scissor, ignored");
            return;
        }

        // Apply current opacity
        let opacity = self.current_opacity();
        if opacity < 1.0 {
            cell.fg = cell.fg.with_opacity(opacity);
            cell.bg = cell.bg.with_opacity(opacity);
        }

        // Alpha composite if background is transparent
        if cell.bg.a() < 255 {
            if let Some(existing) = self.get(x, y) {
                cell.bg = cell.bg.over(existing.bg);
            }
        }

        let idx = self.index(x, y);
        self.cells[idx] = cell;

        // Wide character: set continuation cell
        if cell.width() == 2 && x + 1 < self.width && self.in_scissor(x + 1, y) {
            self.cells[idx + 1] = Cell::CONTINUATION;
        }
    }

    /// Set string at position with style.
    ///
    /// Returns the x position after the last character written.
    pub fn set_string(&mut self, x: u16, y: u16, s: &str, style: Style) -> u16 {
        let mut pos_x = x;
        for grapheme in s.graphemes(true) {
            if pos_x >= self.width {
                break;
            }

            let width = unicode_width::UnicodeWidthStr::width(grapheme);
            if width == 0 {
                continue; // Skip zero-width chars
            }

            let cell = Cell::new(grapheme, style);
            self.set(pos_x, y, cell);
            pos_x += width as u16;
        }
        pos_x
    }

    /// Fill area with a cell.
    pub fn fill(&mut self, area: Rect, cell: Cell) {
        let clipped = area.intersection(&self.current_scissor());
        for y in clipped.y..clipped.y + clipped.height {
            for x in clipped.x..clipped.x + clipped.width {
                self.set(x, y, cell.clone());
            }
        }
    }

    /// Clear entire buffer to default cells.
    pub fn clear(&mut self) {
        self.cells.fill(Cell::default());
        debug!("Buffer cleared");
    }

    /// Clear a specific area to default cells.
    pub fn clear_area(&mut self, area: Rect) {
        self.fill(area, Cell::default());
    }
}
