```rust
impl Buffer {
    /// Push opacity multiplier onto stack.
    ///
    /// Effective opacity = product of all stacked values.
    pub fn push_opacity(&mut self, opacity: f32) {
        let current = self.current_opacity();
        let clamped = opacity.clamp(0.0, 1.0);
        self.opacity_stack.push(current * clamped);
        trace!(
            current, new_opacity = clamped, effective = current * clamped,
            stack_depth = self.opacity_stack.len(),
            "Pushed opacity"
        );
    }

    /// Pop opacity value from stack.
    ///
    /// Base opacity (1.0) cannot be popped.
    pub fn pop_opacity(&mut self) {
        if self.opacity_stack.len() > 1 {
            self.opacity_stack.pop();
            trace!(stack_depth = self.opacity_stack.len(), "Popped opacity");
        }
    }

    /// Get current effective opacity (product of stack).
    #[inline]
    pub fn current_opacity(&self) -> f32 {
        *self.opacity_stack.last().unwrap() // Invariant: always ≥1 element
    }
}
